import{o as e,c as a,a as t}from"./app.2ff5982c.js";const s='{"title":"Company settings","description":"","frontmatter":{},"headers":[{"level":2,"title":"Company info","slug":"company-info"},{"level":2,"title":"Interface settings","slug":"interface-settings"},{"level":2,"title":"Licenses:","slug":"licenses"},{"level":2,"title":"Stiles","slug":"stiles"},{"level":2,"title":"Projects","slug":"projects"}],"relativePath":"company.md","lastUpdated":1630960178756}',i={},n=[t('<h1 id="company-settings"><a class="header-anchor" href="#company-settings" aria-hidden="true">#</a> Company settings</h1><p>In the company settings view, company managers and admins can tweak several settings.</p><h2 id="company-info"><a class="header-anchor" href="#company-info" aria-hidden="true">#</a> Company info</h2><p>Company info such a as address, name and email are shown on reports, mails and other templates. Company notifications are sent to the &quot;contact email&quot;.</p><h2 id="interface-settings"><a class="header-anchor" href="#interface-settings" aria-hidden="true">#</a> Interface settings</h2><ul><li>Show QR button: Show a button in the panel viewer that gives the user a QR for the panel.</li><li>Show RFID button: Show a button in the panel viewer that gives the option to register RFID tags.</li><li>Hide &quot;hidden materials&quot; in 3D: Based on the IFC PS config, a part can be detected as hidden material. Those parts can be hidden in the 3D view by default (when you have this checkbox marked).</li><li>Language: This is the default language for the app. Users can change the language if they are allowed by the admin (see the Users table).</li></ul><h2 id="licenses"><a class="header-anchor" href="#licenses" aria-hidden="true">#</a> Licenses:</h2><p>Gives a main overview of the licensing.</p><h2 id="stiles"><a class="header-anchor" href="#stiles" aria-hidden="true">#</a> Stiles</h2><p>Corporate color and logos can be changed. Those will be used also in PDF generation. Sticker banner is a wide logo to be used in some of the sticker presets (like panel QR stickers).</p><h2 id="projects"><a class="header-anchor" href="#projects" aria-hidden="true">#</a> Projects</h2>',11)];i.render=function(t,s,i,o,r,h){return e(),a("div",null,n)};export{s as __pageData,i as default};
